import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse(`{"title":"Simon Willison's Weblog — 2026-05-25","description":"","frontmatter":{"title":"Simon Willison's Weblog — 2026-05-25","date":"2026-05-25T00:00:00.000Z","source":"Simon Willison's Weblog","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-25-simon-willisons-weblog.md","filePath":"research/ai-news/2026-05/2026-05-25-simon-willisons-weblog.md","lastUpdated":1779796674000}`),s={name:"research/ai-news/2026-05/2026-05-25-simon-willisons-weblog.md"};function n(i,e,l,u,h,p){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="🔧-simon-willison-s-weblog-—-2026-05-25" tabindex="-1">🔧 Simon Willison&#39;s Weblog — 2026-05-25 <a class="header-anchor" href="#🔧-simon-willison-s-weblog-—-2026-05-25" aria-label="Permalink to &quot;🔧 Simon Willison&#39;s Weblog — 2026-05-25&quot;">​</a></h1><blockquote><p>datasette / llm-cli 作者；AI 工具工程實踐與安全分析密度最高的個人部落格 來源：<a href="https://simonwillison.net/atom/everything/" target="_blank" rel="noreferrer">Simon Willison&#39;s Weblog</a></p></blockquote><hr><h2 id="datasette-1-0a30" tabindex="-1"><a href="https://simonwillison.net/2026/May/24/datasette/#atom-everything" target="_blank" rel="noreferrer">datasette 1.0a30</a> <a class="header-anchor" href="#datasette-1-0a30" aria-label="Permalink to &quot;[datasette 1.0a30](https://simonwillison.net/2026/May/24/datasette/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-24</em></p><p><strong>Release:</strong> <a href="https://github.com/simonw/datasette/releases/tag/1.0a30" target="_blank" rel="noreferrer">datasette 1.0a30</a></p><p>The big new feature in this alpha is a new customizable &quot;Jump to...&quot; menu, described in detail in <a href="https://datasette.io/blog/2026/jump-menu/" target="_blank" rel="noreferrer">The extensible &quot;Jump to&quot; menu in Datasette 1.0a30</a> on the Datasette blog. You can try it out by hitting <code>/</code> on <a href="https://latest.datasette.io/" target="_blank" rel="noreferrer">latest.datasette.io</a> - it looks like this:</p><p>The new <a href="https://docs.datasette.io/en/latest/plugin_hooks.html#jump-items-sql-datasette-actor-request" target="_blank" rel="noreferrer">jump_items_sql()</a> plugin hook allows plugins to add their own items to the set that&#39;s searched by the plugin.</p><p>Tags: <a href="https://simonwillison.net/tags/projects" target="_blank" rel="noreferrer">projects</a>, <a href="https://simonwillison.net/tags/datasette" target="_blank" rel="noreferrer">datasette</a>, <a href="https://simonwillison.net/tags/annotated-release-notes" target="_blank" rel="noreferrer">annotated-release-notes</a></p><hr><h2 id="datasette-agent-0-1a4" tabindex="-1"><a href="https://simonwillison.net/2026/May/24/datasette-agent/#atom-everything" target="_blank" rel="noreferrer">datasette-agent 0.1a4</a> <a class="header-anchor" href="#datasette-agent-0-1a4" aria-label="Permalink to &quot;[datasette-agent 0.1a4](https://simonwillison.net/2026/May/24/datasette-agent/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-24</em></p><p><strong>Release:</strong> <a href="https://github.com/datasette/datasette-agent/releases/tag/0.1a4" target="_blank" rel="noreferrer">datasette-agent 0.1a4</a></p><p>Taking advantage of the new <a href="https://docs.datasette.io/en/latest/javascript_plugins.html#javascript-plugins-makejumpsections" target="_blank" rel="noreferrer">makeJumpSections()</a> JavaScript plugin hook added in <a href="https://docs.datasette.io/en/latest/changelog.html#a30-2026-05-24" target="_blank" rel="noreferrer">Datasette 1.0a30</a>, <code>datasette-agent</code> now presents this &quot;Start a new agent chat&quot; interface as part of the Jump to menu, any time you hit <code>/</code>:</p><p>Tags: <a href="https://simonwillison.net/tags/datasette" target="_blank" rel="noreferrer">datasette</a>, <a href="https://simonwillison.net/tags/datasette-agent" target="_blank" rel="noreferrer">datasette-agent</a></p><hr><h2 id="datasette-fixtures-0-1a0" tabindex="-1"><a href="https://simonwillison.net/2026/May/24/datasette-fixtures/#atom-everything" target="_blank" rel="noreferrer">datasette-fixtures 0.1a0</a> <a class="header-anchor" href="#datasette-fixtures-0-1a0" aria-label="Permalink to &quot;[datasette-fixtures 0.1a0](https://simonwillison.net/2026/May/24/datasette-fixtures/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-24</em></p><p><strong>Release:</strong> <a href="https://github.com/datasette/datasette-fixtures/releases/tag/0.1a0" target="_blank" rel="noreferrer">datasette-fixtures 0.1a0</a></p><p>One of the smaller features in <a href="https://docs.datasette.io/en/latest/changelog.html#a30-2026-05-24" target="_blank" rel="noreferrer">Datasette 1.0a30</a> is this:</p><blockquote><p>New documented <a href="https://docs.datasette.io/en/latest/testing_plugins.html#datasette-fixtures-populate-fixture-database" target="_blank" rel="noreferrer">datasette.fixtures.populate_fixture_database(conn)</a> helper for creating the fixture database tables used by Datasette&#39;s own tests, intended for plugin test suites.</p></blockquote><p>This new plugin takes advantage of that API. You can try it out using <code>uvx</code> without even installing Datasette like this:</p><pre><code>uvx --prerelease=allow \\
  --with datasette-fixtures datasette \\
  --get /fixtures/roadside_attractions.json
</code></pre><p>Which outputs:</p><pre><code>{
  &quot;ok&quot;: true,
  &quot;next&quot;: null,
  &quot;rows&quot;: [
    {&quot;pk&quot;: 1, &quot;name&quot;: &quot;The Mystery Spot&quot;, &quot;address&quot;: &quot;465 Mystery Spot Road, Santa Cruz, CA 95065&quot;, &quot;url&quot;: &quot;https://www.mysteryspot.com/&quot;, &quot;latitude&quot;: 37.0167, &quot;longitude&quot;: -122.0024},
    {&quot;pk&quot;: 2, &quot;name&quot;: &quot;Winchester Mystery House&quot;, &quot;address&quot;: &quot;525 South Winchester Boulevard, San Jose, CA 95128&quot;, &quot;url&quot;: &quot;https://winchestermysteryhouse.com/&quot;, &quot;latitude&quot;: 37.3184, &quot;longitude&quot;: -121.9511},
    {&quot;pk&quot;: 3, &quot;name&quot;: &quot;Burlingame Museum of PEZ Memorabilia&quot;, &quot;address&quot;: &quot;214 California Drive, Burlingame, CA 94010&quot;, &quot;url&quot;: null, &quot;latitude&quot;: 37.5793, &quot;longitude&quot;: -122.3442},
    {&quot;pk&quot;: 4, &quot;name&quot;: &quot;Bigfoot Discovery Museum&quot;, &quot;address&quot;: &quot;5497 Highway 9, Felton, CA 95018&quot;, &quot;url&quot;: &quot;https://www.bigfootdiscoveryproject.com/&quot;, &quot;latitude&quot;: 37.0414, &quot;longitude&quot;: -122.0725}
  ],
  &quot;truncated&quot;: false
}
</code></pre><p>Tags: <a href="https://simonwillison.net/tags/datasette" target="_blank" rel="noreferrer">datasette</a>, <a href="https://simonwillison.net/tags/uv" target="_blank" rel="noreferrer">uv</a></p><hr><h2 id="quoting-armin-ronacher" tabindex="-1"><a href="https://simonwillison.net/2026/May/24/armin-ronacher/#atom-everything" target="_blank" rel="noreferrer">Quoting Armin Ronacher</a> <a class="header-anchor" href="#quoting-armin-ronacher" aria-label="Permalink to &quot;[Quoting Armin Ronacher](https://simonwillison.net/2026/May/24/armin-ronacher/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-24</em></p><blockquote><p>The most frustrating failure mode right now is that people submit issues that are not in their own voice. They contain an observed problem somewhere, but it has been thrown into a clanker and the clanker reworded it and made a huge mess of it. Typically, it was prompted so badly that the conclusions produced are more often than not inaccurate but always full of confidence. The result is complete guesswork on root causes, fake-minimal repros, suggested implementation strategies, analogies to adjacent but often the wrong code, and long lists of error classes that might or might not matter. [...]</p><p>So at least personally, I increasingly want issue reports to be condensed to what the human actually observed:</p><ol><li>I ran this command.</li><li>I expected this to happen.</li><li>This happened instead.</li><li>Here is the exact error or log.</li></ol></blockquote><p>-- <a href="https://lucumr.pocoo.org/2026/5/24/pi-oss/" target="_blank" rel="noreferrer">Armin Ronacher</a>, on slop issues filed against <a href="https://pi.dev/" target="_blank" rel="noreferrer">Pi</a></p><p>Tags: <a href="https://simonwillison.net/tags/ai" target="_blank" rel="noreferrer">ai</a>, <a href="https://simonwillison.net/tags/github-issues" target="_blank" rel="noreferrer">github-issues</a>, <a href="https://simonwillison.net/tags/llms" target="_blank" rel="noreferrer">llms</a>, <a href="https://simonwillison.net/tags/ai-ethics" target="_blank" rel="noreferrer">ai-ethics</a>, <a href="https://simonwillison.net/tags/open-source" target="_blank" rel="noreferrer">open-source</a>, <a href="https://simonwillison.net/tags/coding-agents" target="_blank" rel="noreferrer">coding-agents</a>, <a href="https://simonwillison.net/tags/generative-ai" target="_blank" rel="noreferrer">generative-ai</a>, <a href="https://simonwillison.net/tags/armin-ronacher" target="_blank" rel="noreferrer">armin-ronacher</a>, <a href="https://simonwillison.net/tags/pi" target="_blank" rel="noreferrer">pi</a>, <a href="https://simonwillison.net/tags/slop" target="_blank" rel="noreferrer">slop</a></p><hr><h2 id="mad-house-—-usborne-creepy-computer-games" tabindex="-1"><a href="https://simonwillison.net/2026/May/24/usborne-mad-house/#atom-everything" target="_blank" rel="noreferrer">Mad House — Usborne Creepy Computer Games</a> <a class="header-anchor" href="#mad-house-—-usborne-creepy-computer-games" aria-label="Permalink to &quot;[Mad House — Usborne Creepy Computer Games](https://simonwillison.net/2026/May/24/usborne-mad-house/#atom-everything)&quot;">​</a></h2><p><em>🔧 Simon Willison&#39;s Weblog | 2026-05-24</em></p><p><strong>Tool:</strong> <a href="https://tools.simonwillison.net/usborne-mad-house" target="_blank" rel="noreferrer">Mad House — Usborne Creepy Computer Games</a></p><p>Via <a href="https://news.ycombinator.com/item?id=48258194" target="_blank" rel="noreferrer">Hacker News</a> I learned that UK publisher Usborne published <a href="https://usborne.com/us/books/computer-and-coding-books" target="_blank" rel="noreferrer">free PDFs of their 1980s Computer Books</a>, some of which I remember working through on my Commodore 64 as a child.</p><p>These were so great! Beautifully illustrated books with fun projects made up of code you could type into your own machine.</p><p>I remember playing &quot;Mad House&quot; typed in from the 1983 book &quot;Creepy Computer Games&quot;, so I fed that PDF <a href="https://claude.ai/share/7b4a5617-f586-4744-b082-1650cab607cb" target="_blank" rel="noreferrer">into Claude</a> and had it build an interactive version of that game in JavaScript and HTML:</p><blockquote><p><code>Build a vanilla JS artifact that exactly recreates the game Mad House from this book, make sure it&#39;s mobile friendly and has a suitable retro aesthetic</code></p><p><code>Credit the book title and link to https://usborne.com/us/books/computer-and-coding-books</code></p></blockquote><p>Tags: <a href="https://simonwillison.net/tags/computer-history" target="_blank" rel="noreferrer">computer-history</a>, <a href="https://simonwillison.net/tags/games" target="_blank" rel="noreferrer">games</a>, <a href="https://simonwillison.net/tags/tools" target="_blank" rel="noreferrer">tools</a></p><hr>`,42)])])}const g=t(s,[["render",n]]);export{m as __pageData,g as default};
